import sys, json
for i, line in enumerate\(sys.stdin\):
    if not line.strip\(\): continue
    obj = json.loads\(line\)
    t = obj.get\('type','?'\)
    if t == 'response_item':
        p = obj['payload']
        role = p.get\('role','?'\)
        if role == 'user' and isinstance\(p.get\('content'\), list\):
            for c in p['content']:
                if c.get\('type'\) == 'input_text':
                    text = c['text'][:80].replace\(chr\(10\),' '\)
                    print\(f'Line {i}: {text}'\)
    elif t == 'session_meta':
        print\(f'--- Session: {obj[\\"payload\\"].get\(\\"id\\",\\"?\\"\)[:12]}'\)
